-- ============================================\n-- Database Verification Script\n-- Run these queries to verify jobs exist\n-- ============================================\n\n-- 1. Check total job count\nSELECT \n    COUNT(*) as total_jobs,\n    COUNT(DISTINCT source) as unique_sources,\n    COUNT(DISTINCT location) as unique_locations\nFROM job;\n\n-- 2. Check jobs by source/platform\nSELECT \n    source,\n    COUNT(*) as job_count\nFROM job\nGROUP BY source\nORDER BY job_count DESC;\n\n-- 3. Check jobs by location\nSELECT \n    location,\n    COUNT(*) as job_count\nFROM job\nWHERE location IS NOT NULL\nGROUP BY location\nORDER BY job_count DESC\nLIMIT 20;\n\n-- 4. Check jobs with specific keywords\nSELECT \n    COUNT(*) as java_developer_count\nFROM job\nWHERE \n    LOWER(title) LIKE '%java%' \n    AND LOWER(title) LIKE '%developer%';\n\n-- 5. Check jobs with either keyword (multi-term)\nSELECT \n    SUM(CASE WHEN LOWER(title) LIKE '%java%' THEN 1 ELSE 0 END) as java_jobs,\n    SUM(CASE WHEN LOWER(title) LIKE '%developer%' THEN 1 ELSE 0 END) as developer_jobs,\n    SUM(CASE WHEN LOWER(title) LIKE '%java%' OR LOWER(title) LIKE '%developer%' THEN 1 ELSE 0 END) as java_or_developer\nFROM job;\n\n-- 6. Check recent jobs\nSELECT \n    id,\n    title,\n    company,\n    location,\n    source,\n    posted_time\nFROM job\nORDER BY posted_time DESC\nLIMIT 10;\n\n-- 7. Check jobs missing location\nSELECT \n    COUNT(*) as jobs_without_location\nFROM job\nWHERE location IS NULL OR location = '';\n\n-- 8. Check job title patterns\nSELECT \n    COUNT(*) as total,\n    COUNT(DISTINCT SUBSTRING(title, 1, 10)) as unique_title_starts\nFROM job\nWHERE title IS NOT NULL;\n\n-- 9. Quick keyword match test\nSELECT \n    title,\n    location,\n    source\nFROM job\nWHERE \n    LOWER(title) LIKE '%developer%'\n    OR LOWER(description) LIKE '%java%'\nLIMIT 5;\n\n-- 10. Check database for issues\nSELECT \n    COUNT(DISTINCT id) as distinct_ids,\n    COUNT(*) as total_rows\nFROM job;\n-- Should be equal; if not, there are duplicates\n